#!/usr/bin/env node

/**
 * Bundle skills + governance content into src/content.js
 *
 * Reads skills from ../../skills/ and governance from ../../.agents/ (excluding
 * .agents/skills/ which is no longer used — /skills/ is the single source of truth).
 *
 * Generates a JS module exporting a FILES object mapping relative paths to content.
 * Key format matches what install.js expects:
 *   - "skills/yellowpages/..."  → installed to <skillPath>/yellowpages/...
 *   - "ETHOS.md", "workflows/..." etc → installed to <governancePath>/...
 *
 * Run: node scripts/bundle-content.js
 */

import fs from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const repoRoot = path.resolve(__dirname, "..", "..", "..");
const skillsDir = path.resolve(repoRoot, "skills");
const agentsDir = path.resolve(repoRoot, ".agents");
const outputFile = path.resolve(__dirname, "..", "src", "content.js");

function walk(dir, base) {
  const entries = [];
  for (const entry of fs.readdirSync(dir, { withFileTypes: true })) {
    const fullPath = path.join(dir, entry.name);
    const relPath = path.join(base, entry.name);
    if (entry.isDirectory()) {
      entries.push(...walk(fullPath, relPath));
    } else if (entry.isFile()) {
      entries.push({ relPath, fullPath });
    }
  }
  return entries;
}

const manifest = {};

// ── Skills: from /skills/ (single source of truth) ──
// Keys are prefixed with "skills/" to match install.js expectations.
if (fs.existsSync(skillsDir)) {
  const skillFiles = walk(skillsDir, "skills");
  for (const { relPath, fullPath } of skillFiles) {
    const content = fs.readFileSync(fullPath, "utf-8");
    const key = relPath.split(path.sep).join("/");
    manifest[key] = content;
  }
  console.log(`  Skills: ${skillFiles.length} files from skills/`);
} else {
  console.error(`Error: skills/ directory not found at ${skillsDir}`);
  process.exit(1);
}

// ── Governance: from /.agents/ (excluding .agents/skills/) ──
if (fs.existsSync(agentsDir)) {
  let govCount = 0;
  const agentFiles = walk(agentsDir, "");
  for (const { relPath, fullPath } of agentFiles) {
    const key = relPath.split(path.sep).join("/");
    // Skip .agents/skills/ — skills come from /skills/ now
    if (key.startsWith("skills/")) continue;
    const content = fs.readFileSync(fullPath, "utf-8");
    manifest[key] = content;
    govCount++;
  }
  console.log(`  Governance: ${govCount} files from .agents/ (skipped .agents/skills/)`);
} else {
  console.warn(`Warning: .agents/ directory not found at ${agentsDir} — skipping governance`);
}

const output = `// Auto-generated by scripts/bundle-content.js
// Sources: skills/ (skills) + .agents/ (governance, excluding .agents/skills/)
// Do not edit manually — run: npm run bundle

export const FILES = ${JSON.stringify(manifest, null, 2)};
`;

fs.writeFileSync(outputFile, output, "utf-8");
console.log(`\nBundled ${Object.keys(manifest).length} files into src/content.js`);
